109	    private SdfAggregateInfoDTO buildSdfAggregateInfoDTO(SdfAggregateInfo sdfAggregate) {
110	        if (sdfAggregate == null || (sdfAggregate.getActivityInfo() == null && sdfAggregate.getWmAdGmvToAdRule() == null) ) {
111	            return null;
112	        }
113	        SdfAggregateInfoDTO sdfAggregateInfo = new SdfAggregateInfoDTO();
114	        SdfAccountActivityInfo activityInfo = sdfAggregate.getActivityInfo();
115	        WmAdGmvToAdRule rule = sdfAggregate.getWmAdGmvToAdRule();
116	        List<SdfAccountBill> bills = sdfAggregate.getSdfAccountBills();
117	        if (rule != null) {
118	            SdfSignInfoDTO sdfSignInfoDTO = new SdfSignInfoDTO();
119	            sdfSignInfoDTO.setSignDate(rule.getStartDate());
120	            sdfSignInfoDTO.setSignStartDate(rule.getStartDate());
121	            sdfSignInfoDTO.setSignEndDate(rule.getEndDate());
122	            sdfSignInfoDTO.setCanActivity(true);
123	            sdfSignInfoDTO.setSignStatus(rule.getActive() == KaCpsGmvRuleActiveType.VALID.getValue()
124	                    ? SdfAdAccountSignStatusEnum.EFFECTIVE.getStatus() : SdfAdAccountSignStatusEnum.INVALID.getStatus());
125	            RuleExtraInfo ruleExtraInfo = JsonUtil.parse(rule.getExtraInfo(), RuleExtraInfo.class);
126	            sdfSignInfoDTO.setSdfBenefitRuleDTO(SdfBenefitRule.convertToSdfBenefitRuleDTO(ruleExtraInfo == null ? null : ruleExtraInfo.getSdfBenefitRule()));
127	            sdfSignInfoDTO.setRuleId(rule.getRuleId());
128	            sdfSignInfoDTO.setActivityId(rule.getFrameId());
129	            // rule中的费率没有乘100，随单返历史逻辑都是乘100的，对外都需要乘100
130	            sdfSignInfoDTO.setCashRatio(rule.getRatio().multiply(BigDecimal.valueOf(100)).toString());
131	            sdfSignInfoDTO.setRedRatio(BigDecimal.ZERO.toString());
132	            sdfSignInfoDTO.setFeatureConfigId(rule.getId());
133	            sdfSignInfoDTO.setRelatedPoiNum(CollectionUtils.size(sdfAggregate.getRelatedPoiIds()));
134	            sdfAggregateInfo.setRuleInfo(sdfSignInfoDTO);
135	        }
136	        if (activityInfo != null) {
137	            SdfAdAccountGray gray = sdfAggregate.getSdfAdAccountGray();
138	            SdfConfigInfoDTO configDTO = new SdfConfigInfoDTO();
139	            configDTO.setActivityId(activityInfo.getActivityId());
140	            configDTO.setRedRatioDecimal(activityInfo.getRedRatioDecimal().toString());
141	            configDTO.setCashRatioDecimal(activityInfo.getCashRatioDecimal().toString());
142	            configDTO.setGuideText(activityInfo.getGuidText());
143	            configDTO.setStartDate(activityInfo.getStartDate());
144	            configDTO.setEndDate(activityInfo.getEndDate());
145	            configDTO.setCashCycleDate(activityInfo.getCashCycleDate());
146	            configDTO.setRedCycleDate(activityInfo.getRedCycleDate());
147	            configDTO.setPoiName(activityInfo.getPoiName());
148	            configDTO.setPartnerId(activityInfo.getPartnerId());
149	            configDTO.setPartnerType(activityInfo.getPartnerType());
150	            configDTO.setSdfBenefitRuleDTO(SdfBenefitRule.convertToSdfBenefitRuleDTO(activityInfo.getBenefitRule()));
151	            configDTO.setFeatureConfigId(activityInfo.getId());
152	            configDTO.setCanWithdraw(gray != null && gray.getWithdrawType() > 0);
153	            configDTO.setCanSelfTermination(gray != null && gray.getTerminationType() > 0);
154	            if (activityInfo.getLaunchStrategy() != null) {
155	                SdfLaunchStrategyDTO launchStrategyDTO = new SdfLaunchStrategyDTO();
156	                launchStrategyDTO.setAdProdType(activityInfo.getLaunchStrategy().getAdProdType());
157	                launchStrategyDTO.setLaunchName(activityInfo.getLaunchStrategy().getLaunchName());
158	                configDTO.setSdfLaunchStrategyDTO(launchStrategyDTO);
159	            }
160	            sdfAggregateInfo.setConfigInfo(configDTO);
161	        }
162	        if (!CollectionUtils.isEmpty(bills)) {
163	            sdfAggregateInfo.setBillInfos(bills.stream().map(e -> {
164	                    SdfBillDTO bill = new SdfBillDTO();
165	                    BeanUtils.copyProperties(e, bill);
166	                    return bill;
167	            }).collect(Collectors.toList()));
168	        }
169	        return sdfAggregateInfo;
170	    }
