184	    @Override
185	    @RpcResponse
186	    @Log
187	    public Result sdfSign(SdfSignReq signReq) throws TException {
188	        Preconditions.checkArgument(signReq != null, "请求参数为空");
189	
190	        if (SdfAdAccountSignOperateTypeEnum.isSign(signReq.getOperateType())) {
191	            int limitShopNum = LionUtil.LION.getIntValue("SdfSignShopLimitNum", 5000);
192	            Preconditions.checkArgument(signReq.getFeatureConfigId() > 0, "参数异常");
193	            Preconditions.checkArgument(CollectionUtils.size(signReq.getDpShopIds()) <= limitShopNum, "门店数量超过限制");
194	
195	            List<Partner> partners = buildSdfConfigPartnerList(signReq.getLoginAccountId(), signReq.getDpShopIds());
196	            SdfSignExtraInfo extraInfo = SdfSignExtraInfo.convertTodSdfSignExtraInfo(signReq.getExtraInfo());
197	            extraInfo.setAcctId(extraInfo.getAcctId() != null &&extraInfo.getAcctId() > 0 ? extraInfo.getAcctId() : signReq.getLoginAccountId());
198	
199	            boolean ret = adAccountSdfAppService.signSdf(signReq.getFeatureConfigId(), signReq.getPartnerId(),
200	                    signReq.getPartnerType(), signReq.getDpShopIds(), extraInfo, partners, signReq.getOperateType());
201	
202	            return ret ? ResultV2Util.success() : ResultV2Util.fail(ResultCodeEnum.SYSTEM_EXCEPTION);
203	        } else if (SdfAdAccountSignOperateTypeEnum.isTerminate(signReq.getOperateType())) {
204	            SdfSignExtraInfo extraInfo = SdfSignExtraInfo.convertTodSdfSignExtraInfo(signReq.getExtraInfo());
205	            boolean ret = adAccountSdfAppService.terminateSdfRule(signReq.getRuleId(), signReq.getOperateType(), extraInfo);
206	            return ret ? ResultV2Util.success() : ResultV2Util.fail(ResultCodeEnum.SYSTEM_EXCEPTION);
207	        } else {
208	            return ResultV2Util.fail(ResultCodeEnum.ILLEGAL_ARGUMENT_ERROR, "不支持的操作类型");
209	        }
210	    }
