212	    @Override
213	    @RpcResponse
214	    @Log
215	    public SdfTransferFlowResp getSdfTransferFlow(SdfTransferFlowQueryReq queryReq) throws TException {
216	        Preconditions.checkArgument(queryReq != null, "请求参数为空");
217	
218	        List<SdfTransferFlow> flows = adAccountSdfAppService.getSdfTransferFlows(
219	                queryReq.getPartnerId(),
220	                queryReq.getPartnerType(),
221	                queryReq.getStartDate(),
222	                queryReq.getEndDate(),
223	                queryReq.getRuleId(),
224	                false
225	        );
226	        Map<Long, List<SdfTransferFlow>> ruleFlowMap = flows.stream().collect(
227	                Collectors.groupingBy(SdfTransferFlow::getDpPoiId, Collectors.toList()));
228	        List<SdfTransferFlowInfoDTO> flowInfos = ruleFlowMap.entrySet().stream().map(entry -> {
229	            Money amount = entry.getValue().stream().map(SdfTransferFlow::getAmount).reduce(Money.ZERO, Money::add);
230	            int startDate = entry.getValue().stream().map(SdfTransferFlow::getDate).min(Integer::compareTo).orElse(0);
231	            int endDate = entry.getValue().stream().map(SdfTransferFlow::getDate).max(Integer::compareTo).orElse(0);
232	            long mtPoiId = entry.getValue().stream().map(SdfTransferFlow::getMtPoiId).findFirst().orElse(0L);
233	
234	            SdfTransferFlowInfoDTO flowInfo = new SdfTransferFlowInfoDTO();
235	            flowInfo.setPartnerId(queryReq.getPartnerId());
236	            flowInfo.setPartnerType(queryReq.getPartnerType());
237	            flowInfo.setDpPoiId(entry.getKey());
238	            flowInfo.setMtPoiId(mtPoiId);
239	            flowInfo.setAmount(amount.toFen().longValue());
240	            flowInfo.setStartDate(startDate);
241	            flowInfo.setEndDate(endDate);
242	            return flowInfo;
243	        }).collect(Collectors.toList());
244	
245	        return new SdfTransferFlowResp().setResult(ResultV2Util.success()).setTransferFlowInfos(flowInfos);
246	    }
