307	    public CanShowSdfResp canShowSdf(CanShowSdfReq req) throws TException {
308	        Preconditions.checkArgument(req != null, "请求参数为空");
309	        Preconditions.checkArgument(CollectionUtils.size(req.getDdAdAccountIds()) <= 1000, "单次请求inner数量超过1000");
310	        Preconditions.checkArgument(CollectionUtils.size(req.getDpPoiIds()) <= 1000, "单次请求门店数量超过1000");
311	
312	        List<Partner> partners = new ArrayList<>();
313	        if (CollectionUtils.isNotEmpty(req.getDdAdAccountIds())) {
314	            partners.addAll(req.getDdAdAccountIds().stream().map(e -> new Partner(e, PartnerType.DD_SHOP_ACCOUNT.getIntValue())).collect(Collectors.toList()));
315	            partners.addAll(req.getDdAdAccountIds().stream().map(e -> new Partner(e, PartnerType.DD_UNIFIED_ACCOUNT.getIntValue())).collect(Collectors.toList()));
316	        }
317	        if (CollectionUtils.isNotEmpty(req.getDpPoiIds())) {
318	            partners.addAll(req.getDpPoiIds().stream().map(e -> new Partner(e, PartnerType.DP_POI.getIntValue())).collect(Collectors.toList()));
319	        }
320	        if (req.getMtAccountId() > 0) {
321	            partners.add(new Partner(req.getMtAccountId(), PartnerType.KDB.getIntValue()));
322	        }
323	
324	        Map<Partner, SdfAdAccountActivity> partnerInUseSdfConfigMap = adAccountSdfAppService.queryPartnerInUseSdfConfig(partners);
325	        Set<Partner> configPartners = partnerInUseSdfConfigMap.keySet();
326	        List<Partner> signPartners = adAccountSdfAppService.querySdfSignPartners(partners);
327	
328	        return new CanShowSdfResp().setResult(ResultV2Util.success())
329	                .setCanMtAccountShow(configPartners.stream().anyMatch(e -> e.getPartnerType() == PartnerType.KDB.getIntValue()))
330	                .setCanShowDpPoiIds(configPartners.stream().filter(e -> e.getPartnerType() == PartnerType.DP_POI.getIntValue()).map(Partner::getPartnerId).collect(Collectors.toSet()))
331	                .setCanShowDdAdAccountIds(signPartners.stream().filter(e -> PartnerType.isDDAccount(e.getPartnerType())).map(Partner::getPartnerId).collect(Collectors.toSet()))
332	                .setBenefitMap(getBenefitRuleInfoMap(partnerInUseSdfConfigMap));
333	    }
