335	    private Map<PartnerDTO, SdfBenefitRuleDTO> getBenefitRuleInfoMap(Map<Partner, SdfAdAccountActivity> partnerInUseSdfConfigMap) {
336	        if (MapUtils.isEmpty(partnerInUseSdfConfigMap)) {
337	            return Collections.emptyMap();
338	        }
339	        Map<PartnerDTO, SdfBenefitRuleDTO> configInfoDTOMap = new HashMap<>();
340	        for (Map.Entry<Partner, SdfAdAccountActivity> entry : partnerInUseSdfConfigMap.entrySet()) {
341	            SdfBenefitRule sdfBenefitRule = JsonUtil.parse(entry.getValue().getBenefitStrategy(), SdfBenefitRule.class);
342	            PartnerDTO partnerDto = new PartnerDTO();
343	            partnerDto.setPartnerId(entry.getKey().getPartnerId());
344	            partnerDto.setPartnerType(entry.getKey().getPartnerType());
345	            configInfoDTOMap.put(partnerDto, SdfBenefitRule.convertToSdfBenefitRuleDTO(sdfBenefitRule));
346	        }
347	        return configInfoDTOMap;
348	    }
