290	    private List<SdfAccountBill> getSdfAccountBills(long partnerId, int partnerType, int startDate, int endDate, long ruleId) {
291	        List<SdfTransferFlow> flows = getSdfTransferFlows(partnerId, partnerType, startDate, endDate, ruleId, true);
292	        Map<Integer, Long> date2Amount = flows.stream().collect(Collectors.groupingBy(
293	                SdfTransferFlow::getDate, Collectors.summingLong(e -> e.getAmount().toFen().longValue())));
