295	            SdfAccountBill sdfAccountBill = new SdfAccountBill();
296	            sdfAccountBill.setDate(e.getKey());
297	            sdfAccountBill.setTransinAmount(e.getValue());
298	            sdfAccountBill.setTransoutAmount(e.getValue());
299	            sdfAccountBill.setGrantAmount(0);
300	            return sdfAccountBill;
301	        }).collect(Collectors.toList());
302	    }
