509	        List<WmAdGmvToAdRule> rules = wmKaGmvToAdDomainService.pageGetRulesByTransferAccount(partners, active, pageSize, offsetNum);
510	        List<WmAdGmvToAdRule> activeRules = rules.stream().filter(rule -> rule.getActive() == KaCpsGmvRuleActiveType.VALID.getValue()).collect(Collectors.toList());
511	        List<WmAdGmvToAdRule> historyRules = rules.stream().filter(rule -> rule.getActive() != KaCpsGmvRuleActiveType.VALID.getValue()).collect(Collectors.toList());
512	        if (!CollectionUtils.isEmpty(activeRules)) {
513	            Map<Long, List<Long>> rule2PoiMap = wmKaGmvToAdDomainService.getPoiIdListByRuleIdList(
514	                    activeRules.stream().map(WmAdGmvToAdRule::getRuleId).collect(Collectors.toList()));
