518	                sdRuleOperateInfoDTO.setRuleInfo(overviewInfoDTO);
519	                sdRuleOperateInfoDTO.setPoiIds(rule2PoiMap.getOrDefault(rule.getRuleId(), Collections.emptyList()));
520	                overviewInfoDTOS.add(sdRuleOperateInfoDTO);
521	            }
522	        }
523	        if (!CollectionUtils.isEmpty(historyRules)) {
524	            List<WmAdGmvToAdRuleSnapshot> snapshots = wmKaGmvToAdDomainService.getRuleSnapshotByRuleIds(historyRules.stream()
525	                    .map(WmAdGmvToAdRule::getRuleId).collect(Collectors.toList()));
526	            Map<Long, SdPoiRuleAndOperateInfoDTO> rule2SnapshotMap = snapshots.stream().collect(
527	                    Collectors.toMap(WmAdGmvToAdRuleSnapshot::getRuleId, snapshot -> {
528	                        SdfRuleOverviewInfoDTO overviewInfoDTO = convertToSdfRuleOverviewInfo(snapshot);
529	                        SdPoiRuleAndOperateInfoDTO sdRuleOperateInfoDTO = new SdPoiRuleAndOperateInfoDTO();
530	                        sdRuleOperateInfoDTO.setRuleInfo(overviewInfoDTO);
531	                        sdRuleOperateInfoDTO.setPoiIds(JsonUtil.toList(snapshot.getPoiIds(), Long.class));
532	                        RuleOperateInfo operateInfo = JsonUtil.parse(snapshot.getOperateInfo(), RuleOperateInfo.class);
533	                        if (operateInfo != null) {
534	                            SdfOperateInfoDTO operateInfoDTO = new SdfOperateInfoDTO();
535	                            operateInfoDTO.setAccountUserName(operateInfo.getAccountUserName());
536	                            operateInfoDTO.setMis(operateInfo.getMis());
537	                            operateInfoDTO.setRemark(operateInfo.getRemark());
538	                            operateInfoDTO.setIp(operateInfo.getIp());
539	                            operateInfoDTO.setAcctId(operateInfo.getAcctId() == null ? 0 : operateInfo.getAcctId());
540	                            operateInfoDTO.setOperateType(operateInfo.getOperateType());
541	                            operateInfoDTO.setToken(operateInfo.getToken());
542	                            operateInfoDTO.setPlanViewId(operateInfo.getPlanViewId() == null ? 0 : operateInfo.getPlanViewId());
543	                            operateInfoDTO.setPlatform(operateInfo.getPlatform() == null ? 0 : operateInfo.getPlatform());
544	                            operateInfoDTO.setOperateTime(snapshot.getCtime());
545	                            sdRuleOperateInfoDTO.setOperateInfo(operateInfoDTO);
546	                        }
547	                        return sdRuleOperateInfoDTO;
548	                    },(a, b) -> a)
549	            );
550	            overviewInfoDTOS.addAll(rule2SnapshotMap.values());
551	        }
552	        pageModel.setTotal(totalCount);
553	        pageModel.setTotalPage((totalCount + pageSize - 1) / pageSize);
554	        pageModel.setRecords(overviewInfoDTOS);
555	        pageModel.setPageNo(pageNum);
556	        pageModel.setPageSize(pageSize);
557	        return pageModel;
558	    }
