582	    public boolean terminateSdfRule(long ruleId, int operateType, SdfSignExtraInfo extraInfo) {
583	        String lockKey = "lock_sdf_sign_" + ruleId;
584	        try {
585	            Boolean isLock = kvService.setnxByRedis(lockKey, RedisCategory.COMMON_CATEGORY_TEN_MINUTES, "1", 30);
586	            if (!isLock) {
587	                throw new RuntimeException("当前协议正在解约中，请稍后重试");
588	            }
589	
590	            RuleOperateInfo operateInfo = new RuleOperateInfo();
591	            BeanUtils.copyProperties(extraInfo, operateInfo);
592	            operateInfo.setOperateType(operateType);
593	            WmAdGmvToAdRule rule = wmKaGmvToAdDomainService.getRuleByRuleId(ruleId);
594	            if (rule == null) {
595	                return true;
596	            }
597	
598	            int ret = wmKaGmvToAdDomainService.closeRule(rule.getRuleId(), operateInfo);
599	            if (ret > 0) {
600	                RuleExtraInfo ruleExtraInfo = JsonUtil.parse(rule.getExtraInfo(), RuleExtraInfo.class);
601	                if (ruleExtraInfo == null) {
602	                    String info = String.format("extraInfo is null, ruleId=%s&extraInfo=%s", rule.getRuleId(), rule.getExtraInfo());
603	                    Cat.logEvent("SDF", "PostActionFail", "1", info);
604	                    log.error("terminateSdfRule error, info:{}", info);
605	                    return true;
606	                }
607	                SdfAdAccountActivity activity = adAccountSdfService.getActivityById(ruleExtraInfo.getActivityConfigId());
608	                if (activity == null) {
609	                    String info = String.format("activity is null, ruleId=%s&extraInfo=%s", rule.getRuleId(), rule.getExtraInfo());
610	                    Cat.logEvent("SDF", "PostActionFail", "1", info);
611	                    log.error("terminateSdfRule error, info:{}", info);
612	                    return true;
613	                }
614	                SdfLaunchStrategy launchStrategy = JsonUtil.parse(activity.getLaunchStrategy(), SdfLaunchStrategy.class);
615	                SdfBenefitRule benefitRule = ruleExtraInfo.getSdfBenefitRule();
616	                SdfCouponInfo couponInfo = benefitRule == null ? null : benefitRule.getSdfCouponInfo();
617	
618	                SdfPostActionParam param = new SdfPostActionParam();
619	                param.setSignId(rule.getRuleId());
620	                param.setPartnerId(rule.getToKaAcctId());
621	                param.setPartnerType(getPartnerTypeByTransferType(rule.getTransferType()));
622	                param.setOperateType(operateType);
623	                param.setLaunchStrategy(launchStrategy);
624	                param.setCouponInfo(couponInfo);
625	                param.setExtraInfo(extraInfo);
626	                postAction(param);
627	
628	            }
629	            return ret > 0;
630	        } catch (Exception e) {
631	            log.error("AdAccountSdfAppService.terminateSdfSign is error, ruleId:{} operateType:{}", ruleId, operateType, e);
632	        } finally{
633	            kvService.compareAndDelete(lockKey, "1", RedisCategory.COMMON_CATEGORY_TEN_MINUTES);
634	        }
635	
636	        return false;
637	    }
