691	                adAccountOrderBackSign.setSignDate(today);
692	                adAccountOrderBackSign.setPartnerId(partnerId);
693	                adAccountOrderBackSign.setPartnerType(partnerType);
694	                adAccountOrderBackSign.setCashCycleStartDate(today);
695	            }
696	
697	            // 根据参数设置本次应该修改的数据
698	            int distantDay = LionUtil.LION.getIntValue("ad_account_sdf.sign_distant_day", 24990101);
699	            adAccountOrderBackSign.setCashCycleEndDate(distantDay);
700	            adAccountOrderBackSign.setStatus(isEffective ? 1 : 2);
701	            // 目前确定业务只能设置 1%、2%... 表里存的是单位是%，上游传的是%后两位
702	            if (ratio % 100 > 0) {
703	                log.error("AdAccountSdfAppService.toggleSdfSign unsupported ratio set. partnerId: {}, ratio: {}", partnerId, ratio);
704	            }
705	            adAccountOrderBackSign.setCashRatio(ratio / 100);
706	            adAccountOrderBackSign.setCashRatioDecimal(new BigDecimal(ratio).divide(new BigDecimal(100), 1, RoundingMode.DOWN));
707	
708	            boolean result = adAccountSdfService.saveSdfSign(SdfAdAccountSignOperateTypeEnum.FULL_SITE_SIGN.getType(), adAccountOrderBackSign, null);
709	            log.info("AdAccountSdfAppService.toggleSdfSign save. result: {} adAccountOrderBackSign: {}", result, adAccountOrderBackSign);
710	            if (result) {
711	                signPostAction(SdfAdAccountSignOperateTypeEnum.SYSTEM_SIGN.getType(), adAccountOrderBackSign, null, null);
712	                return new Result(true, 0, "success");
713	            }
714	        } catch (Exception e) {
715	            log.error("AdAccountSdfAppService.toggleSdfSign Exception. partnerId: {}, partnerType: {}, activityName: {}, status: {}, ratio: {}",
716	                    partnerId, partnerType, activityName, isEffective, ratio, e);
717	        }
718	        return new Result(false, 1, "未成功设置单返活动！");
