821	    private BigDecimal getSdfRedPackRatio(SdfAdAccountSign signInfo) {
822	        int today = DateTimeUtil.getYesterday();
823	
824	        SdfBenefitRule sdfBenefitRule = JsonUtil.parse(signInfo.getBenefitStrategy(), SdfBenefitRule.class);
825	        if (sdfBenefitRule != null && !CollectionUtils.isEmpty(sdfBenefitRule.getSdfRedPackStageRules())) {
826	            BigDecimal redRatioDecimal = BigDecimal.ZERO;
827	            for (SdfRedPackStage sdfRedPackStage : sdfBenefitRule.getSdfRedPackStageRules()) {
828	                if (today >= sdfRedPackStage.getStartDate() && today <= sdfRedPackStage.getEndDate()) {
829	                    redRatioDecimal = redRatioDecimal.add(sdfRedPackStage.getRatio());
830	                }
831	            }
832	            return redRatioDecimal;
833	        }
834	        return signInfo.getRedRatioDecimal();
835	    }
