1023	    private int getEndDate(int date, int offsetDays) {
1024	        if (offsetDays == -1) {
1025	            return FOREVER_DAY;
1026	        }
1027	        int endDate = DateTimeUtil.plusDays(date, offsetDays);
1028	        return Math.min(endDate, FOREVER_DAY);
1029	    }
