1465	    private void addRedPackStrategy(SdfBenefitRule rule, String[] activity, int startId) {
1466	        BigDecimal redRatioStage1 = new BigDecimal(activity[startId].replaceAll("﻿","").trim());
1467	        int redCycleDateStage1 = Integer.parseInt(activity[startId + 1].replaceAll("﻿","").trim());
1468	        BigDecimal redRatioStage2 = new BigDecimal(activity[startId + 2].replaceAll("﻿","").trim());
1469	        int redCycleDateStage2 = Integer.valueOf(activity[startId + 3].replaceAll("﻿","").trim());
1470	        int redCycleStartDateStage2 = Integer.valueOf(activity[startId + 4].replaceAll("﻿","").trim());
1471	
1472	        List<SdfRedPackStage> redPackStageRules = new ArrayList<>();
1473	        if (redRatioStage1.compareTo(BigDecimal.ZERO) > 0) {
1474	            SdfRedPackStage item = new SdfRedPackStage();
1475	            item.setRatio(redRatioStage1);
1476	            item.setStartOffsetDays(0);
1477	            item.setEndOffsetDays(redCycleDateStage1 - 1);
1478	            redPackStageRules.add(item);
1479	        }
1480	
1481	        if (redRatioStage2.compareTo(BigDecimal.ZERO) > 0) {
1482	            SdfRedPackStage item = new SdfRedPackStage();
1483	            item.setRatio(redRatioStage2);
1484	            item.setStartOffsetDays(redCycleStartDateStage2);
1485	            item.setEndOffsetDays(redCycleDateStage2 == -1 ? -1 : redCycleStartDateStage2 + redCycleDateStage2 - 1);
1486	            redPackStageRules.add(item);
1487	        }
1488	        rule.setSdfRedPackStageRules(redPackStageRules);
1489	    }
