1597	    public boolean updateSdfFeatureConfig(List<SdfFeatureConfigDTO> sdfFeatureConfigDTOS) {
1598	        if (CollectionUtils.isEmpty(sdfFeatureConfigDTOS)) {
1599	            return true;
1600	        }
1601	        Map<Integer, SdfLaunchStrategy> getSdfLaunchStrategyConfig = getSdfLaunchStrategyConfig();
1602	        Map<SdfCouponInfo, Long> couponAmountMap = new HashMap<>();
1603	        List<SdfAdAccountActivity> accountActivities = new ArrayList<>();
1604	        for (SdfFeatureConfigDTO configDTO : sdfFeatureConfigDTOS) {
1605	            // 合法性校验：超过阈值时按阈值处理
1606	            BigDecimal cashRatioInput = new BigDecimal(configDTO.getCashRatio());
1607	            BigDecimal redRatioInput = new BigDecimal(configDTO.getRedRatio());
1608	            BigDecimal stage2RedRatioInput = new BigDecimal(configDTO.getStage2RedRatio());
1609	            BigDecimal cashRatio = cashRatioInput.min(CASH_RATIO_LIMIT);
1610	            BigDecimal redRatio = redRatioInput.min(RED_RATIO_LIMIT);
1611	            BigDecimal stage2RedRatio = stage2RedRatioInput.min(RED_RATIO_LIMIT);
1612	            // 超出阈值时记录错误日志
1613	            if (cashRatioInput.compareTo(CASH_RATIO_LIMIT) > 0) {
1614	                log.error("[SDF] 现金比例超出阈值, accountId:{}, activityId:{}, 输入值:{}, 阈值:{}", configDTO.getPartnerIds(), configDTO.getActivityId(), cashRatioInput, CASH_RATIO_LIMIT);
1615	            }
1616	            if (redRatioInput.compareTo(RED_RATIO_LIMIT) > 0) {
1617	                log.error("[SDF] 红包比例超出阈值, accountId:{}, activityId:{}, 输入值:{}, 阈值:{}", configDTO.getPartnerIds(), configDTO.getActivityId(), redRatioInput, RED_RATIO_LIMIT);
1618	            }
1619	            if (stage2RedRatioInput.compareTo(RED_RATIO_LIMIT) > 0) {
1620	                log.error("[SDF] 二阶段红包比例超出阈值, accountId:{}, activityId:{}, 输入值:{}, 阈值:{}", configDTO.getPartnerIds(), configDTO.getActivityId(), stage2RedRatioInput, RED_RATIO_LIMIT);
1621	            }
1622	            for (Long partnerId : configDTO.getPartnerIds()) {
1623	                SdfBenefitRule rule = new SdfBenefitRule();
1624	                addRedPackStrategy(rule, configDTO, redRatio, stage2RedRatio);
1625	                addCouponStrategy(rule, configDTO, couponAmountMap);
1626	                int maxCycleDate = rule.getSdfRedPackStageRules().stream().map(SdfRedPackStage::getEndOffsetDays).max(Integer::compareTo).orElse(0);
1627	                int minCycleDate = rule.getSdfRedPackStageRules().stream().map(SdfRedPackStage::getEndOffsetDays).min(Integer::compareTo).orElse(0);
1628	
1629	                SdfAdAccountActivity activity = new SdfAdAccountActivity();
1630	                activity.setGuideText(configDTO.getGuideText());
1631	                activity.setActivityId(configDTO.getActivityId());
1632	                activity.setActivityName(configDTO.getActivityName());
1633	                activity.setPartnerId(partnerId);
1634	                activity.setPartnerType(configDTO.getPartnerType());
1635	                activity.setCashRatioDecimal(cashRatio);
1636	                activity.setCashCycleDate(configDTO.getCashCycleDate());
1637	
1638	                activity.setRedCycleDate(minCycleDate == -1 ? -1 : maxCycleDate);
1639	                activity.setStartDate(configDTO.getStartDate());
1640	                activity.setEndDate(configDTO.getEndDate());
1641	                activity.setStatus(configDTO.getStatus());
1642	                activity.setBenefitStrategy(JsonUtil.toJson(rule));
1643	                activity.setSystemSign(configDTO.getSystemSign());
1644	                activity.setSource(configDTO.getSource());
1645	                if (configDTO.getAdProdType() > 0) {
1646	                    SdfLaunchStrategy launchStrategy = getSdfLaunchStrategyConfig.get(configDTO.getAdProdType());
1647	                    activity.setLaunchStrategy(JsonUtil.toJson(launchStrategy));
1648	                }
1649	                if (activity.getRedCycleDate() == -1) {
1650	                    log.warn("返红包周期不允许配置为-1, accountId:{} activityId:{}", partnerId, activity.getActivityId());
1651	                    continue;
1652	                }
1653	
1654	                accountActivities.add(activity);
1655	            }
1656	        }
1657	        int ret = batchCreateSdfActivityAndSign(accountActivities);
1658	        return ret == accountActivities.size();
1659	    }
