1685	    private void addCouponStrategy(SdfBenefitRule rule, SdfFeatureConfigDTO featureConfigDTO, Map<SdfCouponInfo, Long> couponAmoutMap) {
1686	        if (featureConfigDTO.getCouponTemplateId() <= 0) {
1687	            return;
