1690	        sdfCouponInfo.setCouponTemplateId(featureConfigDTO.getCouponTemplateId());
1691	        sdfCouponInfo.setBenefitTemplateId(featureConfigDTO.getBenefitTemplateId());
1692	        if (!couponAmoutMap.containsKey(sdfCouponInfo)) {
1693	            if (featureConfigDTO.getPartnerType() == PartnerType.POI.getIntValue()) {
1694	                long couponAmount = wmCouponProxy.getCouponAmountByTemplateId(featureConfigDTO.getCouponTemplateId(), featureConfigDTO.getBenefitTemplateId());
1695	                couponAmoutMap.put(sdfCouponInfo, couponAmount);
1696	            } else if (featureConfigDTO.getPartnerType() == PartnerType.DP_POI.getIntValue()
1697	                || featureConfigDTO.getPartnerType() == PartnerType.KDB.getIntValue()) {
1698	                Money amount = ddBenefitProxy.getBenefitTemplateAmount(Math.toIntExact(featureConfigDTO.getBenefitTemplateId()), BenefitTypeEnum.DISCOUNT);
1699	                couponAmoutMap.put(sdfCouponInfo, amount.toFen().longValue());
1700	            }
1701	        }
1702	        sdfCouponInfo.setCouponAmount(couponAmoutMap.get(sdfCouponInfo));
1703	        rule.setSdfCouponInfo(sdfCouponInfo);
1704	    }
