1706	    /**
1707	     * AI签约随单返
1708	     * @param partnerId        门店ID
1709	     * @param partnerType      门店类型
1710	     * @param operateType      操作类型
1711	     * @param extraInfo        额外信息
1712	     * @return 结果
1713	     */
1714	    public Result aiSignSdf(long partnerId, int partnerType, int operateType, SdfSignExtraInfo extraInfo) {
1715	        log.info("[AdAccountSdfAppService.aiSignSdf] is start,partnerId:{}, partnerType:{}, operateType:{}, extraInfo:{}", partnerId, partnerType, operateType, extraInfo);
1716	        String errorMsg = StringUtils.EMPTY;
1717	        int retryCount = 0;
1718	        // 多次尝试签约随单返
1719	        while (retryCount < LionUtil.LION.getIntValue("sdf_sign_retry_count", 3)) {
1720	            extraInfo.setTryCount(retryCount);
1721	            extraInfo.setSignStatus(true);
1722	
1723	            // 调用现有接口实现签约
1724	            Result result = saveSdfSign(partnerId, partnerType, operateType, extraInfo);
1725	            if (result.isSuccess()) {
1726	                log.info("[AdAccountSdfAppService.aiSignSdf] is success,partnerId:{}, partnerType:{}", partnerId, partnerType);
1727	                if (IDEMPOTENT_CODE == result.getCode()) {
1728	                    result.setSuccess(false);
1729	                    errorMsg = result.getMessage();
1730	                    retryCount++;
1731	                    // 幂等成功后不继续重试
1732	                    break;
1733	                } else {
1734	                    return result;
1735	                }
1736	            }
1737	            errorMsg = result.getMessage();
1738	            retryCount++;
1739	        }
1740	
1741	        // 重试次数用尽后仍失败
1742	        log.info("[AdAccountSdfAppService.aiSignSdf] is fail,partnerId:{}, partnerType:{}, errorMsg:{}", partnerId, partnerType, errorMsg);
1743	        // 1. 补偿操作记录
1744	        extraInfo.setTryCount(retryCount);
1745	        extraInfo.setSignStatus(false);
1746	        extraInfo.setErrorMsg(errorMsg);
1747	        int rows = adAccountSdfService.saveSignOperate(operateType, extraInfo);
1748	        if (rows != 1) {
1749	            log.error("[AdAccountSdfAppService.aiSignSdf] 补偿操作记录失败, partnerId:{}", partnerId);
1750	        }
1751	
1752	        // 2. 大象通知
1753	        String title = "AI外呼签约随单返失败";
1754	        String content = "AI外呼签约随单返失败，签约门店id:" + partnerId + ", 失败原因:" + errorMsg;
1755	        signSdfDXAlarm(title, content);
1756	
1757	        // 3. 最终结果
1758	        log.info("[AdAccountSdfAppService.aiSignSdf] end");
1759	        return new Result(false, 1, errorMsg);
1760	    }
