      sdfSignExtraInfo.setPlanViewId(dto.getPlanViewId() > 0 ? dto.getPlanViewId() : null);
      sdfSignExtraInfo.setLaunchExtendInfo("billing-order-rebate-page");
      sdfSignExtraInfo.setSignSourceCode(dto.getSignSourceCode());  // 第1348行: signSourceCode被赋值
